#!/bin/bash
# ============================================================
# ping-search-engines.sh
#
# Tells Google (and Bing) that the sitemap has been refreshed.
# Run this AFTER every deploy to cuongthai.com — it costs
# nothing and gets new content indexed a few hours faster than
# waiting for the next crawl cycle.
#
# Why "ping" instead of just submitting once?
#   - The sitemap itself is auto-regenerated by Next.js every
#     hour (see frontend/src/app/sitemap.ts, revalidate=3600).
#   - But search engines only recrawl the sitemap occasionally
#     (a few days to a few weeks, depending on the site).
#   - A ping tells them "hey, new content, come look now".
#
# Why also Bing?
#   - Same effect, costs nothing.
#   - Bing powers DuckDuckGo, Yahoo, and a chunk of international
#     search, so showing up there is also organic traffic.
# ============================================================

set -euo pipefail

SITEMAP_URL="https://cuongthai.com/sitemap.xml"
INDEXING_ENDPOINT="https://cuongthai.com/api/index-url"
LAST_INDEXED_FILE="/opt/cuonghoangdev/.last-indexed-urls.txt"

# ─── Google ────────────────────────────────────────────────
# Google deprecated the &ping= URL in 2023 and now returns 404
# for any ping request (verified 2026-06-17). The replacement
# is the Indexing API (see indexnow_ping below) and submitting
# via Search Console. The sitemap itself is still discovered
# via the robots.txt reference, so search engines will find
# the new content on their next crawl — we just can't
# short-circuit that any more.
#
# We keep the function around for now in case Google brings
# back a public ping endpoint, but the call is best-effort.
#
# Reference:
#   https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap
google_ping() {
  local url="https://www.google.com/ping?sitemap=${SITEMAP_URL}"
  local response
  response=$(curl -sS --max-time 10 -o /dev/null -w "%{http_code}" "$url" 2>&1) || true
  if [[ "$response" =~ ^2 ]]; then
    echo "[$(date '+%H:%M:%S')] [✅ OK]  Google ping accepted (HTTP $response)"
  else
    # Non-fatal. Search engines will pick up the new sitemap
    # on their next crawl. To actively push URLs, use
    # Indexing API or IndexNow below.
    echo "[$(date '+%H:%M:%S')] [INFO]  Google ping returned HTTP $response (no-op; legacy endpoint deprecated)"
  fi
}

# ─── Bing ──────────────────────────────────────────────────
# Bing also deprecated the legacy sitemap ping (returns 410
# Gone as of 2024). IndexNow is the replacement.
bing_ping() {
  local url="https://www.bing.com/ping?sitemap=${SITEMAP_URL}"
  local response
  response=$(curl -sS --max-time 10 -o /dev/null -w "%{http_code}" "$url" 2>&1) || true
  if [[ "$response" =~ ^2 ]]; then
    echo "[$(date '+%H:%M:%S')] [✅ OK]  Bing ping accepted (HTTP $response)"
  else
    echo "[$(date '+%H:%M:%S')] [INFO]  Bing ping returned HTTP $response (no-op; legacy endpoint deprecated)"
  fi
}

# ─── IndexNow (Bing + Yandex + Seznam + navboost) ─────────
# IndexNow is the modern replacement for the legacy sitemap
# pings. Submitting a key proves you own the site and lets
# multiple engines pick up the change within minutes.
#
# To enable:
#   1. Generate a UUID once: `uuidgen`
#   2. Save it as frontend/public/INDEXNOW_KEY.txt (one-time
#      proof of ownership — search engines will GET that file
#      to confirm you control the domain)
#   3. Set INDEXNOW_KEY env var to the same value
#   4. Uncomment the block below
#
# For now this is disabled because we don't have a key set up
# yet. The legacy pings above are enough to get indexed.
#
# indexnow_ping() {
#   local key="${INDEXNOW_KEY:-}"
#   [[ -z "$key" ]] && { echo "[SKIP] INDEXNOW_KEY not set"; return 0; }
#   local body="{\"host\":\"cuongthai.com\",\"key\":\"$key\",\"keyLocation\":\"https://cuongthai.com/$key.txt\",\"urlList\":[\"$SITEMAP_URL\"]}"
#   local response
#   response=$(curl -sS --max-time 10 -X POST "https://api.indexnow.org/indexnow" \
#     -H "Content-Type: application/json" \
#     -d "$body" -o /dev/null -w "%{http_code}") || true
#   if [[ "$response" =~ ^2 ]]; then
#     echo "[$(date '+%H:%M:%S')] [✅ OK]  IndexNow accepted (HTTP $response)"
#   else
#     echo "[$(date '+%H:%M:%S')] [WARN]  IndexNow returned HTTP $response (non-fatal)"
#   fi
# }

echo "[$(date '+%H:%M:%S')] [INFO]  Pinging search engines for: $SITEMAP_URL"
google_ping
bing_ping
# indexnow_ping   # enable when INDEXNOW_KEY is set up

# ─── Google Indexing API (active push) ─────────────────────
# Google's old &ping= URL was deprecated in 2023. The active
# way to tell Google "hey, this URL changed, please crawl it
# now" is the Indexing API. We call our own /api/index-url
# route, which uses the service account configured in
# frontend/src/config/google-key.json to talk to Google.
#
# To avoid burning the 200/day quota on every deploy (we deploy
# multiple times per day, but only a fraction of those deploys
# add new content), we diff the current sitemap against the
# last deploy's URL list and only submit URLs that are new.
#
# The diff is stored in /opt/cuonghoangdev/.last-indexed-urls.txt
# so it persists across deploys. If the file is missing (first
# deploy on a fresh VPS), we submit all sitemap URLs and save
# the result.
#
# This block is best-effort: a failure here MUST NOT fail the
# deploy. The route itself is rate-limited at 60s/URL, so for
# 50+ new URLs the loop can take 50+ minutes; we cap with
# MAX_INDEX_PER_DEPLOY (default 20) and the rest get picked up
# on the next deploy.
google_indexing_api_ping() {
  local max_per_deploy="${MAX_INDEX_PER_DEPLOY:-20}"

  # Bail out if the service-account key isn't on the VPS yet.
  # deploy-vps.sh warns about this; we just skip silently.
  if [ ! -f /opt/cuonghoangdev/frontend/src/config/google-key.json ]; then
    echo "[$(date '+%H:%M:%S')] [SKIP] google-key.json missing on VPS — Indexing API disabled"
    return 0
  fi

  # Fetch the current sitemap. Sort + unique so the diff is
  # stable across deploys (sitemap order can change as routes
  # are added/removed).
  local current_urls
  current_urls=$(curl -sS --max-time 15 "$SITEMAP_URL" \
    | grep -oE '<loc>[^<]+</loc>' \
    | sed -E 's#</?loc>##g' \
    | sort -u) || {
    echo "[$(date '+%H:%M:%S')] [WARN] Could not fetch sitemap, skipping Indexing API"
    return 0
  }

  if [ -z "$current_urls" ]; then
    echo "[$(date '+%H:%M:%S')] [SKIP] sitemap is empty, nothing to index"
    return 0
  fi

  # Diff against the last deploy's list.
  local new_urls=()
  if [ -f "$LAST_INDEXED_FILE" ]; then
    while IFS= read -r url; do
      [ -z "$url" ] && continue
      if ! grep -qxF "$url" "$LAST_INDEXED_FILE"; then
        new_urls+=("$url")
      fi
    done <<< "$current_urls"
  else
    # First run on a fresh VPS: index everything.
    while IFS= read -r url; do
      [ -n "$url" ] && new_urls+=("$url")
    done <<< "$current_urls"
  fi

  if [ ${#new_urls[@]} -eq 0 ]; then
    echo "[$(date '+%H:%M:%S')] [INFO]  No new URLs since last deploy, skipping Indexing API"
    return 0
  fi

  # Cap the batch to avoid running forever in CI. The rest
  # get submitted on the next deploy.
  if [ ${#new_urls[@]} -gt "$max_per_deploy" ]; then
    echo "[$(date '+%H:%M:%S')] [INFO]  ${#new_urls[@]} new URLs; capping at $max_per_deploy this run"
    new_urls=("${new_urls[@]:0:$max_per_deploy}")
  fi

  echo "[$(date '+%H:%M:%S')] [INFO]  Indexing ${#new_urls[@]} new URLs via Indexing API..."

  local success=0
  local failed=0
  local url
  for url in "${new_urls[@]}"; do
    local resp
    resp=$(curl -sS --max-time 30 -w "\n%{http_code}" \
      -X POST "$INDEXING_ENDPOINT" \
      -H "Content-Type: application/json" \
      -d "{\"url\":\"$url\"}" 2>&1) || {
      echo "[$(date '+%H:%M:%S')] [WARN]  curl failed for $url"
      failed=$((failed + 1))
      continue
    }
    local code
    code=$(echo "$resp" | tail -1)
    local body
    body=$(echo "$resp" | head -n -1)

    if [ "$code" = "200" ]; then
      success=$((success + 1))
      echo "[$(date '+%H:%M:%S')] [✅ OK]  Indexed: $url"
    elif [ "$code" = "429" ]; then
      # Already submitted recently. Don't count as failure.
      echo "[$(date '+%H:%M:%S')] [INFO]  Already indexed recently: $url"
    else
      failed=$((failed + 1))
      echo "[$(date '+%H:%M:%S')] [WARN]  HTTP $code for $url: $body"
      # On 403 the SA doesn't own the property — stop the
      # batch so we don't burn quota on a config problem.
      if [ "$code" = "403" ]; then
        echo "[$(date '+%H:%M:%S')] [WARN]  Stopping batch: PERMISSION_DENIED. Add SA as Owner in Search Console."
        break
      fi
    fi

    # Throttle: route allows 60s/URL, we wait 65s to be safe.
    sleep 65
  done

  # Persist the *current* full URL list (not just what we
  # successfully submitted) so the diff on the next deploy
  # is against the current sitemap, not a partial submission.
  # Use sudo since /opt/cuonghoangdev is root-owned.
  echo "$current_urls" > "$LAST_INDEXED_FILE.tmp" && \
    mv "$LAST_INDEXED_FILE.tmp" "$LAST_INDEXED_FILE"

  echo "[$(date '+%H:%M:%S')] [OK]   Indexing API: $success ok, $failed failed, ${#new_urls[@]} attempted"
}

google_indexing_api_ping
echo "[$(date '+%H:%M:%S')] [OK]   Done"
